BEGIN TRANSACTION;
CREATE TABLE "flight_weather_logs" (
    date TEXT NOT NULL,
    flight_number TEXT NOT NULL,
    scheduled_time TEXT,
    status TEXT,
    wind_direction REAL,
    wind_speed REAL,
    wind_gusts REAL,
    cloud_cover_low REAL,
    visibility REAL,
    created_at TEXT DEFAULT CURRENT_TIMESTAMP,
    status_reason TEXT,
    UNIQUE(date, flight_number)
);
COMMIT;

